// Redis cache stampede prevention
const mutex = new Map();
async function getWithStampedeProtection(key, ttl, fetchFn) {
  const cached = await redis.get(key);
  // Probabilistic early expiry: 10% chance to refresh before TTL
  if (cached && Math.random() > 0.1) return JSON.parse(cached);
  // Single-flight: only one fetch per key at a time
  if (mutex.has(key)) return mutex.get(key);
  const promise = fetchFn().then(async (data) => {
    await redis.setex(key, ttl, JSON.stringify(data));
    mutex.delete(key);
    return data;
  });
  mutex.set(key, promise);
  return promise;
}
